package com.vidaysalud.veterinaria.citaservicio.model;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;@Entity @Table(name="cita") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Cita{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="id_cita")private Integer idCita;@Column(name="id_mascota",nullable=false)private Integer idMascota;@Column(name="id_veterinario",nullable=false)private Integer idVeterinario;@Column(name="fecha_hora",nullable=false)private LocalDateTime fechaHora;@Enumerated(EnumType.STRING) @Column(nullable=false)private EstadoCita estado;@Column(length=255)private String motivo;@Column(length=500)private String observaciones;@Column(name="fecha_creacion",nullable=false,updatable=false)private LocalDateTime fechaCreacion;@PrePersist void pre(){if(estado==null)estado=EstadoCita.Pendiente;if(fechaCreacion==null)fechaCreacion=LocalDateTime.now();}}